solution_code:
#include <iostream>
#include <iomanip>

class Circle {
public:
    double radius;

    double area() {
        return 3.14159 * radius * radius;
    }

    double perimeter() {
        return 2 * 3.14159 * radius;
    }
};

int main() {
    double r;
    std::cin >> r;
    Circle circle;
    circle.radius = r;
    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Area: " << circle.area() << "\n";
    std::cout << "Perimeter: " << circle.perimeter() << "\n";
    return 0;
}

