solution_code:
#include <iostream>
#include <iomanip>

class Temperature {
public:
    double fahrenheit;

    double toCelsius() {
        return (fahrenheit - 32) * 5.0 / 9.0;
    }
};

int main() {
    double f;
    std::cin >> f;
    Temperature t;
    t.fahrenheit = f;
    std::cout << std::fixed << std::setprecision(2);
    std::cout << t.toCelsius() << " C\n";
    return 0;
}
